-- ----------------------------------------------------------------------------
-- vw_venues: Table: Venues
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_venues WITH (security_invoker = ON) AS
SELECT
  t.venue_id,                                                                   -- Unique venue identifier (slug)
  calc_venues_name(t.venue_id) AS name,                                         -- Display name for the venue
  t.location,                                                                   -- Physical location/address
  t.capacity                                                                    -- Total seating capacity
FROM venues t;

-- ----------------------------------------------------------------------------
-- vw_speakers: Table: Speakers
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_speakers WITH (security_invoker = ON) AS
SELECT
  t.speaker_id,                                                                 -- Unique speaker identifier (email)
  calc_speakers_name(t.speaker_id) AS name,                                     -- Display name for the speaker
  t.availability_start,                                                         -- Start of speaker availability window
  t.availability_end,                                                           -- End of speaker availability window
  calc_speakers_assignment_count(t.speaker_id) AS assignment_count,             -- Total number of event assignments for this speaker
  calc_speakers_is_overbooked(t.speaker_id) AS is_overbooked                    -- Is speaker assigned to more than 3 events (workload alert)?
FROM speakers t;

-- ----------------------------------------------------------------------------
-- vw_events: Table: Events
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_events WITH (security_invoker = ON) AS
SELECT
  t.event_id,                                                                   -- Unique event identifier
  calc_events_name(t.event_id) AS name,                                         -- Display name for the event
  t.venue,                                                                      -- Related venue
  calc_events_venue_capacity(t.event_id) AS venue_capacity,                     -- Looked up venue capacity
  t.event_date,                                                                 -- Event date and start time
  t.duration_minutes,                                                           -- Event duration in minutes
  t.category,                                                                   -- Event category or track (e.g. Tech, Community, Learning)
  calc_events_event_end(t.event_id) AS event_end,                               -- Calculated end time
  calc_events_total_speakers_assigned(t.event_id) AS total_speakers_assigned,   -- Count of speakers assigned to this event
  calc_events_has_speakers(t.event_id) AS has_speakers,                         -- Is at least one speaker assigned?
  calc_events_booked_capacity(t.event_id) AS booked_capacity,                   -- Total attendees booked for this event
  calc_events_available_capacity(t.event_id) AS available_capacity,             -- Remaining capacity after bookings
  calc_events_at_capacity(t.event_id) AS at_capacity,                           -- Is event at or over capacity?
  calc_events_venue_conflict_count(t.event_id) AS venue_conflict_count,         -- Count of other events at same venue within 30 min window
  calc_events_has_venue_conflict(t.event_id) AS has_venue_conflict,             -- Are there venue scheduling conflicts?
  calc_events_event_status(t.event_id) AS event_status,                         -- Event readiness status
  t.registration_close_days_before_event,                                       -- Number of days before the event that registration closes
  calc_events_registration_deadline(t.event_id) AS registration_deadline,       -- Calculated registration deadline (EventDate minus RegistrationCloseDaysBeforeEvent)
  calc_events_is_registration_open(t.event_id) AS is_registration_open,         -- Is registration still open (before deadline)?
  calc_events_capacity_headroom(t.event_id) AS capacity_headroom,               -- Available capacity minus booked attendees
  calc_events_has_headroom_for_overbooking(t.event_id) AS has_headroom_for_overbooking,-- Is there enough headroom to safely overbook by 20%?
  calc_events_recommended_overbooking_factor(t.event_id) AS recommended_overbooking_factor-- Safe overbooking multiplier (if headroom allows)
FROM events t;

-- ----------------------------------------------------------------------------
-- vw_assignments: Table: Assignments (many-to-many: Events to Speakers)
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_assignments WITH (security_invoker = ON) AS
SELECT
  t.assignment_id,                                                              -- Unique assignment identifier
  calc_assignments_name(t.assignment_id) AS name,                               -- Display name
  t.event_ref,                                                                  -- Related event
  t.speaker_ref,                                                                -- Related speaker
  calc_assignments_event_date(t.assignment_id) AS event_date,                   -- Looked up event date
  calc_assignments_speaker_avail_start(t.assignment_id) AS speaker_avail_start, -- Looked up speaker availability start
  calc_assignments_speaker_avail_end(t.assignment_id) AS speaker_avail_end,     -- Looked up speaker availability end
  calc_assignments_is_available(t.assignment_id) AS is_available                -- Is speaker available for this event?
FROM assignments t;

-- ----------------------------------------------------------------------------
-- vw_attendees: Table: Attendees
