-- ----------------------------------------------------------------------------
-- vw_rsvps: Table: RSVPs (many-to-many: Events to Attendees)
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_rsvps WITH (security_invoker = ON) AS
SELECT
  t.rsvp_id,                                                                    -- Unique RSVP identifier
  calc_rsvps_name(t.rsvp_id) AS name,                                           -- Display name
  t.event_ref,                                                                  -- Related event
  t.attendee_ref,                                                               -- Related attendee
  t.status                                                                      -- RSVP status (confirmed, waitlist, declined)
FROM rsvps t;

